description:
Implement enumerate() and enumerator_len() for JinjaPromptValue - these power {% for %} loops and |length filter, with budget enforcement.

Location: crates/baml-bridge/src/prompt/jinja.rs

```rust
impl Object for JinjaPromptValue {
    fn enumerate(self: &Arc<Self>) -> Enumerator {
        match &self.pv.ty {
            TypeIR::List(_, _) | _ if matches!(&self.pv.value, BamlValue::List(_)) => {
                // List iteration with cap
                let actual_len = self.list_len();
                let capped_len = actual_len.min(self.pv.session.settings.max_list_items);
                Enumerator::Seq(capped_len)
            }
            TypeIR::Class { name, mode, .. } => {
                // Class: iterate over declared fields in schema order
                if let Some(class) = self.pv.world.types.find_class(name, *mode) {
                    let keys: Vec<Value> = class.fields.iter()
                        .take(self.pv.session.settings.max_map_entries)
                        .map(|f| Value::from(f.name.real_name().to_string()))
                        .collect();
                    Enumerator::Values(keys)
                } else {
                    Enumerator::Empty
                }
            }
            TypeIR::Map(_, _, _) | _ if matches!(&self.pv.value, BamlValue::Map(_)) => {
                // Map: iterate over keys, sorted lexicographically for determinism
                let keys: Vec<Value> = self.map_keys_sorted()
                    .into_iter()
                    .take(self.pv.session.settings.max_map_entries)
                    .map(Value::from)
                    .collect();
                Enumerator::Values(keys)
            }
            _ => Enumerator::Empty,
        }
    }

    fn enumerator_len(self: &Arc<Self>) -> Option<usize> {
        // Return CAPPED length (not full length)
        // Use __full_len__ for actual size
        match self.enumerate() {
            Enumerator::Seq(n) => Some(n),
            Enumerator::Values(v) => Some(v.len()),
            _ => None,
        }
    }
}
```

Critical behavior:
- |length returns CAPPED length (what iteration would see)
- Use __full_len__ for actual size
- Map keys sorted lexicographically for determinism
- Class fields in schema order
